{
  "name": "Gemini Smart QR Studio",
  "description": "A professional-grade QR code generator that uses Gemini AI to analyze links and suggest creative descriptions and optimized titles for your codes."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface QRCodeConfig {
  value: string;
  size: number;
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H';
  includeMargin: boolean;
  title?: string;
  description?: string;
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AISuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getSmartContext = async (url: string): Promise<AISuggestion> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this URL and suggest a professional title, a short catchy description (max 15 words), and a HEX color that matches its brand vibe: ${url}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            suggestedColor: { type: Type.STRING, description: "HEX color code starting with #" },
          },
          required: ["title", "description", "suggestedColor"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");
    return JSON.parse(text) as AISuggestion;
  } catch (error) {
    console.error("Gemini context error:", error);
    return {
      title: "New QR Code",
      description: "Scan to open the link.",
      suggestedColor: "#000000",
    };
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { QRCodeCanvas } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2,
  ExternalLink,
  Plus
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR, AISuggestion } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 256,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: true,
  title: '',
  description: ''
};

export default function App() {
