    const { name, value } = e.target;
    setConfig(prev => ({ ...prev, [name]: value }));
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Please enter a valid URL (starting with http/https)");
      return;
