    const canvas = document.querySelector('canvas');
    if (canvas) {
      const url = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.png`;
      link.href = url;
      link.click();
    }
