                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Short summary..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Appearance
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Foreground</label>
                <div className="flex items-center gap-2">
                  <input
                    type="color"
                    name="fgColor"
                    value={config.fgColor}
                    onChange={handleInputChange}
                    className="w-10 h-10 rounded-lg cursor-pointer bg-transparent"
                  />
                  <input
                    type="text"
                    name="fgColor"
                    value={config.fgColor}
                    onChange={handleInputChange}
                    className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Background</label>
                <div className="flex items-center gap-2">
                  <input
                    type="color"
                    name="bgColor"
                    value={config.bgColor}
                    onChange={handleInputChange}
                    className="w-10 h-10 rounded-lg cursor-pointer bg-transparent"
                  />
                  <input
                    type="text"
                    name="bgColor"
                    value={config.bgColor}
                    onChange={handleInputChange}
                    className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Error Correction</label>
                <select
                  name="level"
                  value={config.level}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none"
                >
                  <option value="L">Low (7%)</option>
                  <option value="M">Medium (15%)</option>
                  <option value="Q">Quartile (25%)</option>
                  <option value="H">High (30%)</option>
                </select>
              </div>
            </div>
          </div>
        </div>

        {/* Right Column: Preview */}
        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-lg border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-wider mb-2">Live Preview</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Ready to generate"}</h3>
              <p className="text-sm text-slate-500 mt-1 truncate px-4">{config.description || "Enter a URL above to see the result"}</p>
            </div>

            <div 
              ref={qrRef}
              className="p-4 bg-white rounded-2xl shadow-inner border border-slate-100 flex items-center justify-center mb-8"
              style={{ width: 'min-content' }}
            >
              {config.value ? (
                <QRCodeCanvas
                  value={config.value}
                  size={config.size}
                  fgColor={config.fgColor}
                  bgColor={config.bgColor}
                  level={config.level}
                  includeMargin={config.includeMargin}
