                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%)</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Column: Preview */}
        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-lg border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-wider mb-2">Xem trước trực tiếp</span>
