              style={{ backgroundColor: config.bgColor }}
            >
              {config.value ? (
                <>
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 400)} // Caps preview size for UI consistency, download uses actual config.size
                    fgColor={config.fgColor}
                    bgColor={config.bgColor}
                    level={config.level}
                    includeMargin={config.includeMargin}
                  />
                  <div 
                    className="mt-4 font-bold tracking-widest text-center" 
                    style={{ 
                      color: config.fgColor,
                      fontSize: `${Math.max(12, Math.floor(Math.min(config.size, 400) / 15))}px`
                    }}
                  >
                    QUÉT ĐỂ TRUY CẬP
                  </div>
                </>
              ) : (
                <div 
                  className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl flex flex-center flex-col items-center justify-center"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-medium">Đang chờ nội dung...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-xl font-semibold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-3 border border-slate-200 text-slate-700 rounded-xl font-semibold hover:bg-slate-50 disabled:opacity-50 transition-all"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-1">Đường dẫn hiện tại</p>
                  <p className="text-sm font-medium text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={handleCopy} className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* History Section */}
      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Gần đây</h2>
            <p className="text-slate-500 text-sm">Được lưu cục bộ trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xóa toàn bộ lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-medium hover:text-red-600"
            >
              Xóa tất cả
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-slate-100/50 border-2 border-dashed border-slate-200 rounded-3xl p-12 text-center">
            <History className="w-10 h-10 text-slate-300 mx-auto mb-4" />
            <p className="text-slate-400 font-medium italic">Lịch sử sẽ xuất hiện sau khi bạn lưu mã QR đầu tiên.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-4 rounded-2xl border border-slate-200 hover:shadow-md transition-all flex items-center gap-4 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-lg">
                  <QRCodeCanvas
                    value={item.value}
                    size={48}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate">{item.title || "Không có tiêu đề"}</h4>
                  <p className="text-xs text-slate-500 truncate">{item.value}</p>
                  <p className="text-[10px] text-slate-400 mt-1">{new Date(item.createdAt).toLocaleDateString()}</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Persistent CTA Bar */}
      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-slate-200 p-4 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
            <p className="text-xs font-medium text-slate-600">Phiên làm việc đang chạy</p>
          </div>
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">v1.1.0 Optimized</p>
        </div>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2,
  ExternalLink,
  Plus,
  Maximize2
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: true,
  title: '',
  description: ''
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const qrRef = useRef<HTMLDivElement>(null);
  const svgHiddenRef = useRef<SVGSVGElement>(null);

  // Load history from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  // Save history when it changes
  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleDownload = () => {
    if (!config.value) return;

    const text = "QUÉT ĐỂ TRUY CẬP";
    const textHeight = Math.max(40, Math.floor(config.size * 0.15));

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      // Clone the SVG to modify it for export
      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', config.size.toString());
      svgClone.setAttribute('height', (config.size + textHeight).toString());
      svgClone.setAttribute('viewBox', `0 0 ${config.size} ${config.size + textHeight}`);

      // Create text element for SVG
      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (config.size / 2).toString());
      textElement.setAttribute("y", (config.size + textHeight / 2).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${Math.max(12, Math.floor(config.size / 15))}px`);
      textElement.textContent = text;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = document.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = config.size;
      canvas.height = config.size + textHeight;

      // Fill background
      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw QR Code scaled to the requested size
      ctx.drawImage(qrCanvas, 0, 0, config.size, config.size);

      // Draw Text on a single line
      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${Math.max(14, Math.floor(config.size / 15))}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      // Ensure it doesn't wrap by using a single fillText call
      ctx.fillText(text, canvas.width / 2, config.size + (textHeight / 2) - 5);

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 0.92 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Hidden SVG for Export Generation */}
      <div className="hidden">
        {config.value && (
          <QRCodeSVG
            ref={svgHiddenRef}
            value={config.value}
            size={config.size}
            fgColor={config.fgColor}
            bgColor={config.bgColor}
            level={config.level}
            includeMargin={config.includeMargin}
          />
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini Powered</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Input & Config */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                    <Maximize2 className="w-4 h-4" /> Độ phân giải xuất ({config.size}px)
                  </label>
                  <input
                    type="range"
                    name="size"
                    min="128"
                    max="1280"
                    step="8"
                    value={config.size}
                    onChange={handleInputChange}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                  />
                  <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                    <span>128PX</span>
                    <span>1280PX</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
