        {/* Right Column: Preview */}
        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              ref={qrRef}
              className="p-8 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full"
              style={{ backgroundColor: config.bgColor }}
            >
              {config.value ? (
                <>
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 320)}
                    fgColor={config.fgColor}
                    bgColor={config.bgColor}
                    level={config.level}
                    includeMargin={config.includeMargin}
                  />
                  <div 
                    className="mt-6 font-bold tracking-[0.2em] text-center whitespace-nowrap overflow-hidden text-ellipsis w-full" 
                    style={{ 
                      color: config.fgColor,
                      fontSize: `${Math.max(12, Math.floor(Math.min(config.size, 320) / 14))}px`
                    }}
                  >
                    QUÉT ĐỂ TRUY CẬP
                  </div>
                </>
              ) : (
                <div 
                  className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* History Section */}
      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Persistent CTA Bar */}
      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Sẵn sàng xuất file</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.0 PRO</p>
