  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2,
  ExternalLink,
  Plus,
  Maximize2
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: true,
  title: '',
  description: ''
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const qrRef = useRef<HTMLDivElement>(null);
  const svgHiddenRef = useRef<SVGSVGElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";

  // Load history from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  // Save history when it changes
  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleDownload = () => {
    if (!config.value) return;

    // Calculate font size to roughly match QR width
    // "Quét để truy cập" is ~17 characters. 
    // Heuristic: Font size around Size / 8.5 fills the width well for Inter Bold.
    const fontSize = Math.floor(config.size / 8.5);
    const textHeight = fontSize * 1.8;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', config.size.toString());
      svgClone.setAttribute('height', (config.size + textHeight).toString());
      svgClone.setAttribute('viewBox', `0 0 ${config.size} ${config.size + textHeight}`);

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (config.size / 2).toString());
      textElement.setAttribute("y", (config.size + textHeight / 2).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = document.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = config.size;
      canvas.height = config.size + textHeight;

      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.drawImage(qrCanvas, 0, 0, config.size, config.size);

      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, config.size + (textHeight / 2) - (fontSize * 0.1));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 0.92 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <QRCodeSVG
            ref={svgHiddenRef}
            value={config.value}
            size={config.size}
            fgColor={config.fgColor}
            bgColor={config.bgColor}
            level={config.level}
            includeMargin={config.includeMargin}
          />
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini Powered</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                    <Maximize2 className="w-4 h-4" /> Độ phân giải xuất ({config.size}px)
                  </label>
                  <input
                    type="range"
                    name="size"
                    min="128"
                    max="1280"
                    step="8"
                    value={config.size}
                    onChange={handleInputChange}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                  />
                  <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                    <span>128PX</span>
                    <span>1280PX</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              ref={qrRef}
              className="p-8 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full"
              style={{ backgroundColor: config.bgColor }}
            >
              {config.value ? (
                <>
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 320)}
                    fgColor={config.fgColor}
                    bgColor={config.bgColor}
                    level={config.level}
                    includeMargin={config.includeMargin}
                  />
                  <div 
                    className="mt-6 font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      color: config.fgColor,
                      fontSize: `${Math.floor(Math.min(config.size, 320) / 8.5)}px`,
                      width: `${Math.min(config.size, 320)}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </>
              ) : (
                <div 
                  className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Sẵn sàng xuất file</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.0 PRO</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2 
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: true,
  title: '',
  description: ''
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";
  const TEXT_GAP = 16; // 16px gap as requested

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleDownload = () => {
    if (!config.value) return;

    // Font size: 20% smaller than "full width" ratio. 
    // Full width was ~1/8.5. 80% of that is ~1/10.6.
    const fontSize = Math.floor(config.size / 10.6);
    // Area for text includes the 16px gap plus the font height and some bottom breathing room
    const textHeightArea = TEXT_GAP + fontSize + 8;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', config.size.toString());
      svgClone.setAttribute('height', (config.size + textHeightArea).toString());
      svgClone.setAttribute('viewBox', `0 0 ${config.size} ${config.size + textHeightArea}`);

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (config.size / 2).toString());
      textElement.setAttribute("y", (config.size + TEXT_GAP + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      // Find the specific hidden high-res canvas to avoid scaling blur
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) {
        alert("Lỗi: Không tìm thấy bộ tạo mã nguồn.");
        return;
      }

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = config.size;
      canvas.height = config.size + textHeightArea;

      // Fill background
      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw the crisp high-res QR code
      ctx.drawImage(qrCanvas, 0, 0, config.size, config.size);

      // Draw Text with 16px gap
      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, config.size + TEXT_GAP + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined; // Max quality for JPEG

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Hidden elements for crisp high-res generation */}
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={config.includeMargin}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={config.includeMargin}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                    <Maximize2 className="w-4 h-4" /> Độ phân giải xuất ({config.size}px)
                  </label>
                  <input
                    type="range"
                    name="size"
                    min="128"
                    max="1280"
                    step="8"
                    value={config.size}
                    onChange={handleInputChange}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                  />
                  <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                    <span>128PX</span>
                    <span>1280PX</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-8 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full"
              style={{ backgroundColor: config.bgColor }}
            >
              {config.value ? (
                <>
                  {/* Smaller fixed preview for UI stability */}
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 320)}
                    fgColor={config.fgColor}
                    bgColor={config.bgColor}
                    level={config.level}
                    includeMargin={config.includeMargin}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${TEXT_GAP}px`,
                      color: config.fgColor,
                      fontSize: `${Math.floor(Math.min(config.size, 320) / 10.6)}px`,
                      width: `${Math.min(config.size, 320)}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </>
              ) : (
                <div 
                  className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.1 UHD</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2 
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false, // Set to false to handle padding manually for symmetry
  title: '',
  description: ''
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";
  const TEXT_GAP = 16; // 16px gap as requested

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleDownload = () => {
    if (!config.value) return;

    // We calculate a base padding for the entire composition (e.g., 10% of QR size)
    const padding = Math.max(20, Math.floor(config.size * 0.1));
    const fontSize = Math.floor(config.size / 10.6);

    // Total composition dimensions
    const canvasWidth = config.size + (padding * 2);
    // Height = PaddingTop + QR + Gap + FontHeight + PaddingBottom
    const canvasHeight = padding + config.size + TEXT_GAP + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      // Move the QR group by the padding
      const qrGroup = svgClone.querySelector('rect')?.parentElement;
      if (qrGroup) {
        // Since we disabled internal margin, we just offset the whole thing
        svgClone.innerHTML = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="${config.bgColor}" />` + 
                            `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;
      }

      // Create text element for SVG
      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      // Center text vertically in the space between QR and bottom edge
      textElement.setAttribute("y", (padding + config.size + TEXT_GAP + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      // Fill background
      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw high-res QR code with manual padding offset
      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      // Draw Text with 16px gap and symmetric bottom margin
      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      // Y position = PaddingTop + QR + Gap + Half of font height
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + TEXT_GAP + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                    <Maximize2 className="w-4 h-4" /> Độ phân giải xuất ({config.size}px)
                  </label>
                  <input
                    type="range"
                    name="size"
                    min="128"
                    max="1280"
                    step="8"
                    value={config.size}
                    onChange={handleInputChange}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                  />
                  <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                    <span>128PX</span>
                    <span>1280PX</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs uppercase font-mono"
                      />
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-8 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full"
              style={{ backgroundColor: config.bgColor }}
            >
              {config.value ? (
                <>
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 320)}
                    fgColor={config.fgColor}
                    bgColor={config.bgColor}
                    level={config.level}
                    includeMargin={false}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${TEXT_GAP}px`,
                      color: config.fgColor,
                      fontSize: `${Math.floor(Math.min(config.size, 320) / 10.6)}px`,
                      width: `${Math.min(config.size, 320)}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </>
              ) : (
                <div 
                  className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
