            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                    includeMargin={false}
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.3 UHD</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export interface QRCodeConfig {
  value: string;
  size: number;
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H';
  includeMargin: boolean;
  title?: string;
  description?: string;
  bgImage?: string; // Base64 or URL for the background image
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";
  const TEXT_GAP = 16; 

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const handleDownload = async () => {
    if (!config.value) return;

    const padding = Math.max(20, Math.floor(config.size * 0.1));
    const fontSize = Math.floor(config.size / 10.6);
    const canvasWidth = config.size + (padding * 2);
    const canvasHeight = padding + config.size + TEXT_GAP + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      let backgroundContent = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="${config.bgColor}" />`;
      if (config.bgImage) {
        backgroundContent += `<image href="${config.bgImage}" width="${canvasWidth}" height="${canvasHeight}" preserveAspectRatio="xMidYMid slice" />`;
      }

      svgClone.innerHTML = backgroundContent + `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      textElement.setAttribute("y", (padding + config.size + TEXT_GAP + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      if (config.bgImage) {
        try {
          const bgImg = await loadImage(config.bgImage);
          // Cover logic
          const scale = Math.max(canvas.width / bgImg.width, canvas.height / bgImg.height);
          const x = (canvas.width / 2) - (bgImg.width / 2) * scale;
          const y = (canvas.height / 2) - (bgImg.height / 2) * scale;
          ctx.drawImage(bgImg, x, y, bgImg.width * scale, bgImg.height * scale);
        } catch (e) {
          console.error("Failed to draw background image", e);
        }
      }

      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + TEXT_GAP + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="space-y-6">
              {/* Row 1: Export Resolution */}
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <Maximize2 className="w-4 h-4 text-indigo-500" /> Độ phân giải xuất ({config.size}px)
                </label>
                <input
                  type="range"
                  name="size"
                  min="128"
                  max="1280"
                  step="8"
                  value={config.size}
                  onChange={handleInputChange}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                  <span>128PX</span>
                  <span>1280PX</span>
                </div>
              </div>

              {/* Row 2: QR & Background Color */}
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* New Row: Background Image */}
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                 <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <ImageIcon className="w-4 h-4 text-indigo-500" /> Tải ảnh nền (Tùy chọn)
                </label>
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-bold text-slate-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all flex items-center gap-2 shadow-sm"
                  >
                    <ImageIcon className="w-4 h-4" />
                    {config.bgImage ? 'Thay đổi ảnh' : 'Chọn ảnh'}
                  </button>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="hidden"
                  />
                  {config.bgImage && (
                    <div className="flex items-center gap-2 px-2 py-1 bg-white border border-slate-200 rounded-lg">
                      <img src={config.bgImage} alt="Preview" className="w-8 h-8 rounded object-cover border border-slate-100" />
                      <button onClick={removeBgImage} className="p-1 hover:bg-red-50 text-slate-300 hover:text-red-500 transition-colors">
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  )}
                </div>
              </div>

              {/* Row 3: Export Format & Error Level */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-white border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-8 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full relative"
              style={{ 
                backgroundColor: config.bgColor,
                backgroundImage: config.bgImage ? `url(${config.bgImage})` : 'none',
                backgroundSize: 'cover',
                backgroundPosition: 'center'
              }}
            >
              {config.value ? (
                <div className="relative z-10 flex flex-col items-center">
                  <QRCodeCanvas
                    value={config.value}
                    size={Math.min(config.size, 320)}
                    fgColor={config.fgColor}
                    bgColor="transparent"
                    level={config.level}
                    includeMargin={false}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${TEXT_GAP}px`,
                      color: config.fgColor,
                      fontSize: `${Math.floor(Math.min(config.size, 320) / 10.6)}px`,
                      width: `${Math.min(config.size, 320)}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </div>
              ) : (
                <div 
                  className="bg-slate-50/80 backdrop-blur-sm border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60 z-10"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                    includeMargin={false}
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.4 UHD</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";

  // RATIOS based on user requirements for a 300px base:
  // Gap 16px @ 300px QR => 16/300 = 0.0533
  const GAP_RATIO = 16 / 300;
  // Font size 20% smaller than 1/8.5 => 1/10.6 = 0.0943
  const FONT_RATIO = 1 / 10.6;
  // Padding around the composition => 10%
  const PADDING_RATIO = 0.1;

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' ? parseInt(value, 10) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const handleDownload = async () => {
    if (!config.value) return;

    // Scale values proportionally to the export size
    const padding = Math.max(20, Math.floor(config.size * PADDING_RATIO));
    const fontSize = Math.floor(config.size * FONT_RATIO);
    const textGap = Math.floor(config.size * GAP_RATIO);

    const canvasWidth = config.size + (padding * 2);
    // Height ensures Top Margin (padding) == Bottom Margin (padding)
    const canvasHeight = padding + config.size + textGap + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      let backgroundContent = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="${config.bgColor}" />`;
      if (config.bgImage) {
        backgroundContent += `<image href="${config.bgImage}" width="${canvasWidth}" height="${canvasHeight}" preserveAspectRatio="xMidYMid slice" />`;
      }

      svgClone.innerHTML = backgroundContent + `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      textElement.setAttribute("y", (padding + config.size + textGap + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      // Fill background color
      ctx.fillStyle = config.bgColor;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw background image if exists
      if (config.bgImage) {
        try {
          const bgImg = await loadImage(config.bgImage);
          const scale = Math.max(canvas.width / bgImg.width, canvas.height / bgImg.height);
          const x = (canvas.width / 2) - (bgImg.width / 2) * scale;
          const y = (canvas.height / 2) - (bgImg.height / 2) * scale;
          ctx.drawImage(bgImg, x, y, bgImg.width * scale, bgImg.height * scale);
        } catch (e) {
          console.error("Failed to draw background image", e);
        }
      }

      // Draw QR code with padding offset
      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      // Draw Text with proportional gap
      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      // Center of text block: PaddingTop + QR + Gap + half of fontSize
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + textGap + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // UI Clamped values for preview consistency
  const previewSize = Math.min(config.size, 320);
  const previewGap = Math.floor(previewSize * GAP_RATIO);
  const previewFontSize = Math.floor(previewSize * FONT_RATIO);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="space-y-6">
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <Maximize2 className="w-4 h-4 text-indigo-500" /> Độ phân giải xuất ({config.size}px)
                </label>
                <input
                  type="range"
                  name="size"
                  min="128"
                  max="1280"
                  step="8"
                  value={config.size}
                  onChange={handleInputChange}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                  <span>128PX</span>
                  <span>1280PX</span>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu nền</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                 <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <ImageIcon className="w-4 h-4 text-indigo-500" /> Tải ảnh nền (Tùy chọn)
                </label>
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-bold text-slate-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all flex items-center gap-2 shadow-sm"
                  >
                    <ImageIcon className="w-4 h-4" />
                    {config.bgImage ? 'Thay đổi ảnh' : 'Chọn ảnh'}
                  </button>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="hidden"
                  />
                  {config.bgImage && (
                    <div className="flex items-center gap-2 px-2 py-1 bg-white border border-slate-200 rounded-lg">
                      <img src={config.bgImage} alt="Preview" className="w-8 h-8 rounded object-cover border border-slate-100" />
                      <button onClick={removeBgImage} className="p-1 hover:bg-red-50 text-slate-300 hover:text-red-500 transition-colors">
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-white border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-10 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full relative"
              style={{ 
                backgroundColor: config.bgColor,
                backgroundImage: config.bgImage ? `url(${config.bgImage})` : 'none',
                backgroundSize: 'cover',
                backgroundPosition: 'center'
              }}
            >
              {config.value ? (
                <div className="relative z-10 flex flex-col items-center">
                  <QRCodeCanvas
                    value={config.value}
                    size={previewSize}
                    fgColor={config.fgColor}
                    bgColor="transparent"
                    level={config.level}
                    includeMargin={false}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${previewGap}px`,
                      color: config.fgColor,
                      fontSize: `${previewFontSize}px`,
                      width: `${previewSize}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </div>
              ) : (
                <div 
                  className="bg-slate-50/80 backdrop-blur-sm border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60 z-10"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                    includeMargin={false}
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.5 Pro Symmetry</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export interface QRCodeConfig {
  value: string;
  size: number;
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H';
  includeMargin: boolean;
  title?: string;
  description?: string;
  bgImage?: string; // Base64 or URL for the background image
  bgImageOpacity: number; // Opacity value from 0 to 1
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X,
  Layers
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined,
  bgImageOpacity: 1.0
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";

  const GAP_RATIO = 16 / 300;
  const FONT_RATIO = 1 / 10.6;
  const PADDING_RATIO = 0.1;
  const INTERNAL_MARGIN = 0.05; // Extra padding inside the white box around QR

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'number' || name === 'size' || name === 'bgImageOpacity' 
      ? parseFloat(value) 
      : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const handleDownload = async () => {
    if (!config.value) return;

    const padding = Math.max(20, Math.floor(config.size * PADDING_RATIO));
    const fontSize = Math.floor(config.size * FONT_RATIO);
    const textGap = Math.floor(config.size * GAP_RATIO);
    const internalMargin = Math.floor(config.size * INTERNAL_MARGIN);

    const canvasWidth = config.size + (padding * 2);
    const canvasHeight = padding + config.size + textGap + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      let backgroundContent = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="#ffffff" />`;
      if (config.bgImage) {
        backgroundContent += `<image href="${config.bgImage}" width="${canvasWidth}" height="${canvasHeight}" preserveAspectRatio="xMidYMid slice" opacity="${config.bgImageOpacity}" />`;
      }

      // Safe zone background (white patch)
      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);

      backgroundContent += `<rect x="${patchX}" y="${patchY}" width="${patchWidth}" height="${patchHeight}" fill="${config.bgColor}" rx="${Math.floor(config.size * 0.04)}" />`;

      svgClone.innerHTML = backgroundContent + `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      textElement.setAttribute("y", (padding + config.size + textGap + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      // Base layer
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Background image with opacity
      if (config.bgImage) {
        try {
          const bgImg = await loadImage(config.bgImage);
          const scale = Math.max(canvas.width / bgImg.width, canvas.height / bgImg.height);
          const x = (canvas.width / 2) - (bgImg.width / 2) * scale;
          const y = (canvas.height / 2) - (bgImg.height / 2) * scale;
          ctx.save();
          ctx.globalAlpha = config.bgImageOpacity;
          ctx.drawImage(bgImg, x, y, bgImg.width * scale, bgImg.height * scale);
          ctx.restore();
        } catch (e) {
          console.error("Failed to draw background image", e);
        }
      }

      // Safe zone patch (Rounded Rectangle)
      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);
      const radius = Math.floor(config.size * 0.04);

      ctx.fillStyle = config.bgColor;
      ctx.beginPath();
      ctx.moveTo(patchX + radius, patchY);
      ctx.lineTo(patchX + patchWidth - radius, patchY);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY, patchX + patchWidth, patchY + radius);
      ctx.lineTo(patchX + patchWidth, patchY + patchHeight - radius);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY + patchHeight, patchX + patchWidth - radius, patchY + patchHeight);
      ctx.lineTo(patchX + radius, patchY + patchHeight);
      ctx.quadraticCurveTo(patchX, patchY + patchHeight, patchX, patchY + patchHeight - radius);
      ctx.lineTo(patchX, patchY + radius);
      ctx.quadraticCurveTo(patchX, patchY, patchX + radius, patchY);
      ctx.closePath();
      ctx.fill();

      // Draw QR code
      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      // Draw Text
      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + textGap + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const previewSize = Math.min(config.size, 320);
  const previewGap = Math.floor(previewSize * GAP_RATIO);
  const previewFontSize = Math.floor(previewSize * FONT_RATIO);
  const previewInternalMargin = Math.floor(previewSize * INTERNAL_MARGIN);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title || ''}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description || ''}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="space-y-6">
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <Maximize2 className="w-4 h-4 text-indigo-500" /> Độ phân giải xuất ({config.size}px)
                </label>
                <input
                  type="range"
                  name="size"
                  min="128"
                  max="1280"
                  step="8"
                  value={config.size}
                  onChange={handleInputChange}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                  <span>128PX</span>
                  <span>1280PX</span>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu hộp mã (An toàn quét)</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-4">
                 <label className="block text-sm font-medium text-slate-700 flex items-center gap-2">
                  <ImageIcon className="w-4 h-4 text-indigo-500" /> Tải ảnh nền
                </label>
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-bold text-slate-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all flex items-center gap-2 shadow-sm"
                  >
                    <ImageIcon className="w-4 h-4" />
                    {config.bgImage ? 'Thay đổi ảnh' : 'Chọn ảnh'}
                  </button>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="hidden"
                  />
                  {config.bgImage && (
                    <div className="flex items-center gap-2 px-2 py-1 bg-white border border-slate-200 rounded-lg">
                      <img src={config.bgImage} alt="Preview" className="w-8 h-8 rounded object-cover border border-slate-100" />
                      <button onClick={removeBgImage} className="p-1 hover:bg-red-50 text-slate-300 hover:text-red-500 transition-colors">
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  )}
                </div>

                {config.bgImage && (
                  <div className="pt-2">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                      <Layers className="w-3 h-3" /> Độ mờ ảnh nền ({Math.round(config.bgImageOpacity * 100)}%)
                    </label>
                    <input
                      type="range"
                      name="bgImageOpacity"
                      min="0"
                      max="1"
                      step="0.01"
                      value={config.bgImageOpacity}
                      onChange={handleInputChange}
                      className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                    />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-white border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500"
                  >
                    <option value="L">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M">Trung bình (15%)</option>
                    <option value="Q">Cao (25%)</option>
                    <option value="H">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước thực tế</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-10 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full relative min-h-[400px] w-full"
              style={{ 
                backgroundColor: '#ffffff'
              }}
            >
              {/* Actual Background of the whole image */}
              <div className="absolute inset-0 z-0">
                {config.bgImage && (
                  <img 
                    src={config.bgImage} 
                    className="w-full h-full object-cover" 
                    style={{ opacity: config.bgImageOpacity }}
                    alt="" 
                  />
                )}
              </div>

              {config.value ? (
                <div 
                  className="relative z-10 flex flex-col items-center shadow-lg"
                  style={{ 
                    backgroundColor: config.bgColor,
                    padding: `${previewInternalMargin}px`,
                    borderRadius: `${Math.floor(previewSize * 0.04)}px`
                  }}
                >
                  <QRCodeCanvas
                    value={config.value}
                    size={previewSize}
                    fgColor={config.fgColor}
                    bgColor="transparent"
                    level={config.level}
                    includeMargin={false}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${previewGap}px`,
                      color: config.fgColor,
                      fontSize: `${previewFontSize}px`,
                      width: `${previewSize}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </div>
              ) : (
                <div 
                  className="bg-slate-50/80 backdrop-blur-sm border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60 z-10"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                    includeMargin={false}
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.6 SafeScan</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X,
  Layers
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined,
  bgImageOpacity: 1.0
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";

  const GAP_RATIO = 16 / 300;
  const FONT_RATIO = 1 / 10.6;
  const PADDING_RATIO = 0.1;
  const INTERNAL_MARGIN = 0.05;

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    // Đảm bảo các giá trị liên quan đến kích thước và độ mờ được xử lý dưới dạng số
    const isNumeric = name === 'size' || name === 'bgImageOpacity';
    const val = isNumeric ? parseFloat(value) : value;

    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const handleDownload = async () => {
    if (!config.value) return;

    const padding = Math.max(20, Math.floor(config.size * PADDING_RATIO));
    const fontSize = Math.floor(config.size * FONT_RATIO);
    const textGap = Math.floor(config.size * GAP_RATIO);
    const internalMargin = Math.floor(config.size * INTERNAL_MARGIN);

    const canvasWidth = config.size + (padding * 2);
    const canvasHeight = padding + config.size + textGap + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      let backgroundContent = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="#ffffff" />`;
      if (config.bgImage) {
        backgroundContent += `<image href="${config.bgImage}" width="${canvasWidth}" height="${canvasHeight}" preserveAspectRatio="xMidYMid slice" opacity="${config.bgImageOpacity}" />`;
      }

      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);

      backgroundContent += `<rect x="${patchX}" y="${patchY}" width="${patchWidth}" height="${patchHeight}" fill="${config.bgColor}" rx="${Math.floor(config.size * 0.04)}" />`;

      svgClone.innerHTML = backgroundContent + `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      textElement.setAttribute("y", (padding + config.size + textGap + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      if (config.bgImage) {
        try {
          const bgImg = await loadImage(config.bgImage);
          const scale = Math.max(canvas.width / bgImg.width, canvas.height / bgImg.height);
          const x = (canvas.width / 2) - (bgImg.width / 2) * scale;
          const y = (canvas.height / 2) - (bgImg.height / 2) * scale;
          ctx.save();
          ctx.globalAlpha = config.bgImageOpacity;
          ctx.drawImage(bgImg, x, y, bgImg.width * scale, bgImg.height * scale);
          ctx.restore();
        } catch (e) {
          console.error("Failed to draw background image", e);
        }
      }

      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);
      const radius = Math.floor(config.size * 0.04);

      ctx.fillStyle = config.bgColor;
      ctx.beginPath();
      ctx.moveTo(patchX + radius, patchY);
      ctx.lineTo(patchX + patchWidth - radius, patchY);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY, patchX + patchWidth, patchY + radius);
      ctx.lineTo(patchX + patchWidth, patchY + patchHeight - radius);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY + patchHeight, patchX + patchWidth - radius, patchY + patchHeight);
      ctx.lineTo(patchX + radius, patchY + patchHeight);
      ctx.quadraticCurveTo(patchX, patchY + patchHeight, patchX, patchY + patchHeight - radius);
      ctx.lineTo(patchX, patchY + radius);
      ctx.quadraticCurveTo(patchX, patchY, patchX + radius, patchY);
      ctx.closePath();
      ctx.fill();

      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + textGap + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const previewSize = Math.min(config.size, 320);
  const previewGap = Math.floor(previewSize * GAP_RATIO);
  const previewFontSize = Math.floor(previewSize * FONT_RATIO);
  const previewInternalMargin = Math.floor(previewSize * INTERNAL_MARGIN);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
