            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.8 Hybrid Bg</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export interface QRCodeConfig {
  value: string;
  size: number;
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H';
  includeMargin: boolean;
  title?: string;
  description?: string;
  bgImage?: string; // Base64 or URL for the background image
  bgImageOpacity: number; // Opacity value from 0 to 1
  bgImageFit: 'cover' | 'contain'; // How the image fits the background
  bgImageScale: number; // Scale factor for the background image
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X,
  Layers,
  Link as LinkIcon,
  Upload,
  ZoomIn,
  Move
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 300,
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined,
  bgImageOpacity: 1.0,
  bgImageFit: 'cover',
  bgImageScale: 1.0
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const [bgSourceType, setBgSourceType] = useState<'upload' | 'url'>('upload');
  const [bgUrlInput, setBgUrlInput] = useState('');

  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";

  const GAP_RATIO = 16 / 300;
  const FONT_RATIO = 1 / 10.6;
  const PADDING_RATIO = 0.1;
  const INTERNAL_MARGIN = 0.05;

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    const isNumeric = ['size', 'bgImageOpacity', 'bgImageScale'].includes(name);
    const val = isNumeric ? parseFloat(value) : value;

    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUrlImageSubmit = () => {
    if (bgUrlInput.trim()) {
      setConfig(prev => ({ ...prev, bgImage: bgUrlInput.trim() }));
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    setBgUrlInput('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ (bắt đầu bằng http/https)");
      return;
    }

    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    const newQR: GeneratedQR = {
      ...config,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setHistory(prev => [newQR, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const calculateImageMetrics = (canvasW: number, canvasH: number, imgW: number, imgH: number, fit: 'cover' | 'contain', scale: number) => {
    const ratioCanvas = canvasW / canvasH;
    const ratioImg = imgW / imgH;
    let baseScale = 1;

    if (fit === 'cover') {
      baseScale = ratioCanvas > ratioImg ? canvasW / imgW : canvasH / imgH;
    } else {
      baseScale = ratioCanvas > ratioImg ? canvasH / imgH : canvasW / imgW;
    }

    const finalScale = baseScale * scale;
    const drawW = imgW * finalScale;
    const drawH = imgH * finalScale;
    const x = (canvasW - drawW) / 2;
    const y = (canvasH - drawH) / 2;

    return { x, y, drawW, drawH };
  };

  const handleDownload = async () => {
    if (!config.value) return;

    const padding = Math.max(20, Math.floor(config.size * PADDING_RATIO));
    const fontSize = Math.floor(config.size * FONT_RATIO);
    const textGap = Math.floor(config.size * GAP_RATIO);
    const internalMargin = Math.floor(config.size * INTERNAL_MARGIN);

    const canvasWidth = config.size + (padding * 2);
    const canvasHeight = padding + config.size + textGap + fontSize + padding;

    if (exportFormat === 'svg') {
      const svgElement = svgHiddenRef.current;
      if (!svgElement) return;

      const svgClone = svgElement.cloneNode(true) as SVGSVGElement;
      svgClone.setAttribute('width', canvasWidth.toString());
      svgClone.setAttribute('height', canvasHeight.toString());
      svgClone.setAttribute('viewBox', `0 0 ${canvasWidth} ${canvasHeight}`);

      let backgroundContent = `<rect width="${canvasWidth}" height="${canvasHeight}" fill="#ffffff" />`;

      if (config.bgImage) {
        // Simple SVG image handling (SVG doesn't support complex Canvas-like calculations easily without nesting)
        // We'll use preserveAspectRatio for 'fit' simulation
        const aspect = config.bgImageFit === 'cover' ? 'xMidYMid slice' : 'xMidYMid meet';
        backgroundContent += `<image href="${config.bgImage}" width="${canvasWidth}" height="${canvasHeight}" preserveAspectRatio="${aspect}" opacity="${config.bgImageOpacity}" />`;
      }

      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);

      backgroundContent += `<rect x="${patchX}" y="${patchY}" width="${patchWidth}" height="${patchHeight}" fill="${config.bgColor}" rx="${Math.floor(config.size * 0.04)}" />`;

      svgClone.innerHTML = backgroundContent + `<g transform="translate(${padding}, ${padding})">${svgClone.innerHTML}</g>`;

      const textElement = document.createElementNS("http://www.w3.org/2000/svg", "text");
      textElement.setAttribute("x", (canvasWidth / 2).toString());
      textElement.setAttribute("y", (padding + config.size + textGap + (fontSize / 2)).toString());
      textElement.setAttribute("text-anchor", "middle");
      textElement.setAttribute("dominant-baseline", "middle");
      textElement.setAttribute("fill", config.fgColor);
      textElement.setAttribute("font-family", "Inter, sans-serif");
      textElement.setAttribute("font-weight", "bold");
      textElement.setAttribute("font-size", `${fontSize}px`);
      textElement.textContent = DISPLAY_TEXT;

      svgClone.appendChild(textElement);

      const svgData = new XMLSerializer().serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.svg`;
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const qrCanvas = exportCanvasRef.current?.querySelector('canvas');
      if (!qrCanvas) return;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      canvas.width = canvasWidth;
      canvas.height = canvasHeight;

      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      if (config.bgImage) {
        try {
          const bgImg = await loadImage(config.bgImage);
          const metrics = calculateImageMetrics(canvas.width, canvas.height, bgImg.width, bgImg.height, config.bgImageFit, config.bgImageScale);

          ctx.save();
          ctx.globalAlpha = config.bgImageOpacity;
          ctx.drawImage(bgImg, metrics.x, metrics.y, metrics.drawW, metrics.drawH);
          ctx.restore();
        } catch (e) {
          console.error("Failed to draw background image", e);
        }
      }

      const patchX = padding - internalMargin;
      const patchY = padding - internalMargin;
      const patchWidth = config.size + (internalMargin * 2);
      const patchHeight = config.size + textGap + fontSize + (internalMargin * 2);
      const radius = Math.floor(config.size * 0.04);

      ctx.fillStyle = config.bgColor;
      ctx.beginPath();
      ctx.moveTo(patchX + radius, patchY);
      ctx.lineTo(patchX + patchWidth - radius, patchY);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY, patchX + patchWidth, patchY + radius);
      ctx.lineTo(patchX + patchWidth, patchY + patchHeight - radius);
      ctx.quadraticCurveTo(patchX + patchWidth, patchY + patchHeight, patchX + patchWidth - radius, patchY + patchHeight);
      ctx.lineTo(patchX + radius, patchY + patchHeight);
      ctx.quadraticCurveTo(patchX, patchY + patchHeight, patchX, patchY + patchHeight - radius);
      ctx.lineTo(patchX, patchY + radius);
      ctx.quadraticCurveTo(patchX, patchY, patchX + radius, patchY);
      ctx.closePath();
      ctx.fill();

      ctx.drawImage(qrCanvas, padding, padding, config.size, config.size);

      ctx.fillStyle = config.fgColor;
      ctx.font = `bold ${fontSize}px Inter, sans-serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(DISPLAY_TEXT, canvas.width / 2, padding + config.size + textGap + (fontSize / 2));

      const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
      const quality = exportFormat === 'jpeg' ? 1.0 : undefined;

      const url = canvas.toDataURL(mimeType, quality);
      const link = document.createElement('a');
      link.download = `qr-code-${config.title || 'export'}.${exportFormat}`;
      link.href = url;
      link.click();
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadFromHistory = (item: GeneratedQR) => {
    const { id, createdAt, ...rest } = item;
    setConfig(rest);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const previewSize = Math.min(config.size, 320);
  const previewGap = Math.floor(previewSize * GAP_RATIO);
  const previewFontSize = Math.floor(previewSize * FONT_RATIO);
  const previewInternalMargin = Math.floor(previewSize * INTERNAL_MARGIN);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="hidden">
        {config.value && (
          <>
            <QRCodeSVG
              ref={svgHiddenRef}
              value={config.value}
              size={config.size}
              fgColor={config.fgColor}
              bgColor={config.bgColor}
              level={config.level}
              includeMargin={false}
            />
            <div ref={exportCanvasRef}>
              <QRCodeCanvas
                value={config.value}
                size={config.size}
                fgColor={config.fgColor}
                bgColor={config.bgColor}
                level={config.level}
                includeMargin={false}
              />
            </div>
          </>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider hidden sm:inline border border-indigo-100">Gemini AI</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Tạo mã QR
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none pr-32 text-slate-900"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
                    className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm"
                  >
                    {isAnalyzing ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    ) : (
                      <Sparkles className="w-4 h-4" />
                    )}
                    AI Thông minh
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tiêu đề</label>
                  <input
                    type="text"
                    name="title"
                    value={config.title || ''}
                    onChange={handleInputChange}
                    placeholder="Ví dụ: Portfolio"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none text-slate-900"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mô tả</label>
                  <input
                    type="text"
                    name="description"
                    value={config.description || ''}
                    onChange={handleInputChange}
                    placeholder="Thông tin thêm..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none text-slate-900"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Settings className="w-5 h-5 text-indigo-500" />
              Thiết lập hình ảnh
            </h2>

            <div className="space-y-6">
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <label className="block text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                  <Maximize2 className="w-4 h-4 text-indigo-500" /> Độ phân giải xuất ({config.size}px)
                </label>
                <input
                  type="range"
                  name="size"
                  min="128"
                  max="1280"
                  step="8"
                  value={config.size}
                  onChange={handleInputChange}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                <div className="flex justify-between text-[10px] text-slate-400 font-bold mt-1">
                  <span>128PX</span>
                  <span>1280PX</span>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu QR</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="fgColor"
                        value={config.fgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500 text-slate-900"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Màu hộp mã (An toàn quét)</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="w-10 h-10 rounded-lg cursor-pointer bg-transparent border-0"
                      />
                      <input
                        type="text"
                        name="bgColor"
                        value={config.bgColor}
                        onChange={handleInputChange}
                        className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500 text-slate-900"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-4">
                <div className="flex items-center justify-between">
                  <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
                    <ImageIcon className="w-4 h-4 text-indigo-500" /> Tải ảnh nền
                  </label>
                  <div className="flex bg-slate-200/50 p-1 rounded-lg">
                    <button 
                      onClick={() => setBgSourceType('upload')}
                      className={`px-3 py-1 text-[10px] font-bold rounded-md transition-all ${bgSourceType === 'upload' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
                    >
                      MÁY TÍNH
                    </button>
                    <button 
                      onClick={() => setBgSourceType('url')}
                      className={`px-3 py-1 text-[10px] font-bold rounded-md transition-all ${bgSourceType === 'url' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
                    >
                      URL
                    </button>
                  </div>
                </div>

                <div className="space-y-3">
                  {bgSourceType === 'upload' ? (
                    <div className="flex items-center gap-4">
                      <button
                        onClick={() => fileInputRef.current?.click()}
                        className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-indigo-50 hover:border-indigo-200 transition-all flex items-center gap-2 shadow-sm"
                      >
                        <Upload className="w-4 h-4" />
                        {config.bgImage ? 'Thay đổi' : 'Chọn tệp'}
                      </button>
                      <input
                        ref={fileInputRef}
                        type="file"
                        accept="image/*"
                        onChange={handleImageUpload}
                        className="hidden"
                      />
                    </div>
                  ) : (
                    <div className="flex gap-2">
                      <div className="relative flex-1">
                        <input
                          type="text"
                          value={bgUrlInput}
                          onChange={(e) => setBgUrlInput(e.target.value)}
                          placeholder="https://example.com/image.jpg"
                          className="w-full px-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 pr-10"
                        />
                        <LinkIcon className="absolute right-3 top-2.5 w-4 h-4 text-slate-300" />
                      </div>
                      <button 
                        onClick={handleUrlImageSubmit}
                        className="bg-indigo-600 text-white px-4 rounded-xl text-sm font-bold hover:bg-indigo-700 transition-colors"
                      >
                        Áp dụng
                      </button>
                    </div>
                  )}

                  {config.bgImage && (
                    <div className="space-y-4 pt-2 border-t border-slate-200/50 mt-4 animate-in fade-in duration-300">
                      {/* Control: Display Mode */}
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <Move className="w-3 h-3" /> Chế độ hiển thị
                          </label>
                          <div className="flex bg-white border border-slate-200 p-1 rounded-xl">
                            <button 
                              onClick={() => setConfig(prev => ({...prev, bgImageFit: 'cover'}))}
                              className={`flex-1 py-1.5 text-[10px] font-bold rounded-lg transition-all ${config.bgImageFit === 'cover' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
                            >
                              PHỦ KÍN
                            </button>
                            <button 
                              onClick={() => setConfig(prev => ({...prev, bgImageFit: 'contain'}))}
                              className={`flex-1 py-1.5 text-[10px] font-bold rounded-lg transition-all ${config.bgImageFit === 'contain' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
                            >
                              VỪA KHÍT
                            </button>
                          </div>
                        </div>

                        <div className="space-y-2">
                           <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <ZoomIn className="w-3 h-3" /> Thu phóng ({Math.round(config.bgImageScale * 100)}%)
                          </label>
                          <input
                            type="range"
                            name="bgImageScale"
                            min="0.1"
                            max="3.0"
                            step="0.05"
                            value={config.bgImageScale}
                            onChange={handleInputChange}
                            className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600 mt-2"
                          />
                        </div>
                      </div>

                      {/* Control: Opacity */}
                      <div className="space-y-2">
                        <div className="flex justify-between items-center">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <Layers className="w-3 h-3" /> Độ mờ ảnh nền
                          </label>
                          <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded">{Math.round(config.bgImageOpacity * 100)}%</span>
                        </div>
                        <input
                          type="range"
                          name="bgImageOpacity"
                          min="0"
                          max="1"
                          step="0.01"
                          value={config.bgImageOpacity}
                          onChange={handleInputChange}
                          className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                        />
                      </div>

                      {/* Info Badge */}
                      <div className="flex items-center justify-between p-3 bg-white rounded-xl border border-slate-200">
                        <div className="flex items-center gap-3">
                          <div className="relative group">
                            <img src={config.bgImage} alt="Bg" className="w-10 h-10 rounded-lg object-cover border border-slate-100 shadow-sm" />
                            <div className="absolute inset-0 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity cursor-pointer" onClick={removeBgImage}>
                               <X className="text-white w-4 h-4" />
                            </div>
                          </div>
                          <div>
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Đang sử dụng</p>
                            <p className="text-xs font-semibold text-slate-600 truncate max-w-[150px]">
                              {bgSourceType === 'url' ? 'Link Internet' : 'Tệp máy tính'}
                            </p>
                          </div>
                        </div>
                        <button onClick={removeBgImage} className="text-red-500 p-2 hover:bg-red-50 rounded-lg transition-colors">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Định dạng file</label>
                  <div className="flex gap-2">
                    {['png', 'jpeg', 'svg'].map((format) => (
                      <button
                        key={format}
                        onClick={() => setExportFormat(format as any)}
                        className={`flex-1 py-2 px-3 rounded-lg text-xs font-bold border transition-all ${
                          exportFormat === format 
                            ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        {format.toUpperCase()}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Cấp độ sửa lỗi</label>
                  <select
                    name="level"
                    value={config.level}
                    onChange={handleInputChange}
                    className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500 text-slate-900 cursor-pointer"
                  >
                    <option value="L" className="text-slate-900 bg-white">Thấp (7%) - Tối ưu tốc độ</option>
                    <option value="M" className="text-slate-900 bg-white">Trung bình (15%)</option>
                    <option value="Q" className="text-slate-900 bg-white">Cao (25%)</option>
                    <option value="H" className="text-slate-900 bg-white">Rất cao (30%) - Khuyên dùng</option>
                  </select>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Xem trước thực tế</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Sẵn sàng tạo"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4 leading-relaxed">{config.description || "Nhập liên kết để thấy sự thay đổi"}</p>
            </div>

            <div 
              className="p-10 rounded-2xl shadow-inner border border-slate-100 flex flex-col items-center justify-center mb-8 overflow-hidden max-w-full relative min-h-[400px] w-full"
              style={{ backgroundColor: '#ffffff' }}
            >
              <div className="absolute inset-0 z-0 flex items-center justify-center overflow-hidden">
                {config.bgImage && (
                  <div className="w-full h-full relative">
                     {/* Preview logic mirroring Canvas rendering */}
                     <img 
                      src={config.bgImage} 
                      className="absolute block max-w-none transition-all duration-300" 
                      style={{ 
                        opacity: config.bgImageOpacity,
                        width: config.bgImageFit === 'cover' ? '100%' : 'auto',
                        height: config.bgImageFit === 'cover' ? '100%' : 'auto',
                        maxHeight: config.bgImageFit === 'contain' ? '100%' : 'none',
                        maxWidth: config.bgImageFit === 'contain' ? '100%' : 'none',
                        objectFit: config.bgImageFit,
                        transform: `scale(${config.bgImageScale})`,
                        top: '50%',
                        left: '50%',
                        translate: '-50% -50%'
                      }}
                      alt="" 
                    />
                  </div>
                )}
              </div>

              {config.value ? (
                <div 
                  className="relative z-10 flex flex-col items-center shadow-lg"
                  style={{ 
                    backgroundColor: config.bgColor,
                    padding: `${previewInternalMargin}px`,
                    borderRadius: `${Math.floor(previewSize * 0.04)}px`
                  }}
                >
                  <QRCodeCanvas
                    value={config.value}
                    size={previewSize}
                    fgColor={config.fgColor}
                    bgColor="transparent"
                    level={config.level}
                    includeMargin={false}
                  />
                  <div 
                    className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                    style={{ 
                      marginTop: `${previewGap}px`,
                      color: config.fgColor,
                      fontSize: `${previewFontSize}px`,
                      width: `${previewSize}px`
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </div>
              ) : (
                <div 
                  className="bg-slate-50/80 backdrop-blur-sm border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center opacity-60 z-10"
                  style={{ width: 256, height: 256 }}
                >
                  <QrCode className="w-12 h-12 text-slate-300 mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full max-w-sm">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 disabled:bg-slate-200 disabled:cursor-not-allowed transition-all shadow-lg active:scale-95"
              >
                <Download className="w-4 h-4" />
                Lưu {exportFormat.toUpperCase()}
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"
              >
                <History className="w-4 h-4" />
                Lưu trữ
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full max-w-sm p-4 bg-slate-50 rounded-xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.15em] mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} title="Copy link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                  <a href={config.value} target="_blank" rel="noreferrer" title="Open link" className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600 shadow-sm border border-transparent hover:border-slate-100">
                    <ExternalLink className="w-4 h-4" />
                  </a>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <section className="max-w-6xl mx-auto px-4 mt-12 pb-24">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Lịch sử thiết kế</h2>
            <p className="text-slate-500 text-sm">Dữ liệu được lưu trữ an toàn trong trình duyệt của bạn</p>
          </div>
          {history.length > 0 && (
            <button 
              onClick={() => { if(confirm('Xác nhận xóa tất cả lịch sử?')) setHistory([]) }} 
              className="text-sm text-red-500 font-bold hover:text-red-600 px-3 py-1 rounded-lg hover:bg-red-50 transition-colors"
            >
              Xóa lịch sử
            </button>
          )}
        </div>

        {history.length === 0 ? (
          <div className="bg-white border border-slate-200 rounded-3xl p-16 text-center shadow-sm">
            <History className="w-12 h-12 text-slate-200 mx-auto mb-4" />
            <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Trống</p>
            <p className="text-slate-300 text-xs mt-1">Bắt đầu tạo mã QR để lưu trữ chúng tại đây.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {history.map((item) => (
              <div 
                key={item.id} 
                className="group bg-white p-5 rounded-2xl border border-slate-200 hover:shadow-xl hover:border-indigo-100 transition-all flex items-center gap-5 cursor-pointer"
                onClick={() => loadFromHistory(item)}
              >
                <div className="p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:scale-105 transition-transform">
                  <QRCodeCanvas
                    value={item.value}
                    size={56}
                    fgColor={item.fgColor}
                    bgColor={item.bgColor}
                    level="L"
                    includeMargin={false}
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-bold text-slate-900 truncate group-hover:text-indigo-600 transition-colors">{item.title || "Mã QR không tên"}</h4>
                  <p className="text-[11px] text-slate-500 truncate mt-0.5">{item.value}</p>
                  <p className="text-[9px] text-slate-300 font-bold uppercase mt-2 tracking-wider">{new Date(item.createdAt).toLocaleDateString()} • {item.size}PX</p>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleDelete(item.id); }}
                  className="p-2 text-slate-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-lg"
                  title="Xóa"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        )}
      </section>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống sẵn sàng</p>
          </div>
          <div className="flex gap-6 items-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hidden sm:block">Professional Tools for Creative Work</p>
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">v1.2.9 Zoom Controls</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export interface QRCodeConfig {
  value: string;
  size: number; // Đây sẽ là độ phân giải tổng thể của ảnh xuất (ví dụ 1280px)
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H';
  includeMargin: boolean;
  title?: string;
  description?: string;
  bgImage?: string;
  bgImageOpacity: number;
  bgImageFit: 'cover' | 'contain';
  bgImageScale: number;
  qrScale: number; // Tỉ lệ mã QR so với độ rộng ảnh (0.05 đến 1.0)
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { QRCodeCanvas, QRCodeSVG } from 'qrcode.react';
import { 
  QrCode, 
  Download, 
  Trash2, 
  Sparkles, 
  History, 
  Settings, 
  Copy, 
  CheckCircle2, 
  ExternalLink, 
  Plus, 
  Maximize2,
  Image as ImageIcon,
  X,
  Layers,
  Link as LinkIcon,
  Upload,
  ZoomIn,
  Move,
  Layout
} from 'lucide-react';
import { QRCodeConfig, GeneratedQR } from './types';
import { getSmartContext } from './services/geminiService';

const DEFAULT_CONFIG: QRCodeConfig = {
  value: '',
  size: 1024, // Mặc định độ phân giải cao
  fgColor: '#000000',
  bgColor: '#ffffff',
  level: 'H',
  includeMargin: false,
  title: '',
  description: '',
  bgImage: undefined,
  bgImageOpacity: 1.0,
  bgImageFit: 'cover',
  bgImageScale: 1.0,
  qrScale: 0.5 // Mặc định chiếm 50% ảnh
};

export default function App() {
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [history, setHistory] = useState<GeneratedQR[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [copied, setCopied] = useState(false);
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'svg'>('png');
  const [bgSourceType, setBgSourceType] = useState<'upload' | 'url'>('upload');
  const [bgUrlInput, setBgUrlInput] = useState('');

  const svgHiddenRef = useRef<SVGSVGElement>(null);
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const DISPLAY_TEXT = "Quét để truy cập";
  const INTERNAL_MARGIN_RATIO = 0.05;
  const TEXT_GAP_RATIO = 0.05;
  const FONT_SIZE_RATIO = 0.08;

  useEffect(() => {
    const saved = localStorage.getItem('qr_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('qr_history', JSON.stringify(history));
  }, [history]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    const isNumeric = ['size', 'bgImageOpacity', 'bgImageScale', 'qrScale'].includes(name);
    const val = isNumeric ? parseFloat(value) : value;
    setConfig(prev => ({ ...prev, [name]: val }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, bgImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUrlImageSubmit = () => {
    if (bgUrlInput.trim()) {
      setConfig(prev => ({ ...prev, bgImage: bgUrlInput.trim() }));
    }
  };

  const removeBgImage = () => {
    setConfig(prev => ({ ...prev, bgImage: undefined }));
    setBgUrlInput('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!config.value || !config.value.startsWith('http')) {
      alert("Vui lòng nhập URL hợp lệ");
      return;
    }
    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSave = () => {
    if (!config.value) return;
    setHistory(prev => [{ ...config, id: crypto.randomUUID(), createdAt: Date.now() }, ...prev]);
  };

  const handleDelete = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const handleDownload = async () => {
    if (!config.value) return;

    const canvasSize = config.size;
    const qrGroupWidth = canvasSize * config.qrScale;
    const internalMargin = qrGroupWidth * INTERNAL_MARGIN_RATIO;
    const actualQRSize = qrGroupWidth - (internalMargin * 2);
    const textGap = qrGroupWidth * TEXT_GAP_RATIO;
    const fontSize = qrGroupWidth * FONT_SIZE_RATIO;

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    canvas.width = canvasSize;
    canvas.height = canvasSize;

    // 1. Nền trắng cơ bản
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 2. Vẽ ảnh nền
    if (config.bgImage) {
      try {
        const bgImg = await loadImage(config.bgImage);
        const ratioCanvas = canvas.width / canvas.height;
        const ratioImg = bgImg.width / bgImg.height;
        let drawScale = 1;

        if (config.bgImageFit === 'cover') {
          drawScale = ratioCanvas > ratioImg ? canvas.width / bgImg.width : canvas.height / bgImg.height;
        } else {
          drawScale = ratioCanvas > ratioImg ? canvas.height / bgImg.height : canvas.width / bgImg.width;
        }

        const finalScale = drawScale * config.bgImageScale;
        const dw = bgImg.width * finalScale;
        const dh = bgImg.height * finalScale;
        const dx = (canvas.width - dw) / 2;
        const dy = (canvas.height - dh) / 2;

        ctx.save();
        ctx.globalAlpha = config.bgImageOpacity;
        ctx.drawImage(bgImg, dx, dy, dw, dh);
        ctx.restore();
      } catch (e) {
        console.error("BG Image Load Error", e);
      }
    }

    // 3. Vẽ Vùng an toàn (Safe Patch)
    const patchX = (canvas.width - qrGroupWidth) / 2;
    const patchY = (canvas.height - (qrGroupWidth + textGap + fontSize)) / 2;
    const patchW = qrGroupWidth;
    const patchH = qrGroupWidth + textGap + fontSize + internalMargin;
    const radius = qrGroupWidth * 0.05;

    ctx.fillStyle = config.bgColor;
    ctx.beginPath();
    ctx.roundRect(patchX, patchY, patchW, patchH, radius);
    ctx.fill();

    // 4. Vẽ QR Code (Lấy từ hidden canvas để giữ độ nét cao)
    const qrCanvas = document.createElement('canvas');
    qrCanvas.width = actualQRSize * 2; // Supersampling
    qrCanvas.height = actualQRSize * 2;

    // Chúng ta cần vẽ lại mã QR vào một canvas tạm với kích thước chuẩn
    const tempCanvas = exportCanvasRef.current?.querySelector('canvas');
    if (tempCanvas) {
      ctx.drawImage(tempCanvas, patchX + internalMargin, patchY + internalMargin, actualQRSize, actualQRSize);
    }

    // 5. Vẽ Văn bản
    ctx.fillStyle = config.fgColor;
    ctx.font = `bold ${fontSize}px Inter, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.fillText(DISPLAY_TEXT, canvas.width / 2, patchY + internalMargin + actualQRSize + textGap);

    const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
    const link = document.createElement('a');
    link.download = `smart-qr-${Date.now()}.${exportFormat}`;
    link.href = canvas.toDataURL(mimeType, 1.0);
    link.click();
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(config.value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const previewSize = 320;
  const previewQRWidth = previewSize * config.qrScale;
  const previewInternalMargin = previewQRWidth * INTERNAL_MARGIN_RATIO;
  const previewActualQRSize = previewQRWidth - (previewInternalMargin * 2);
  const previewTextGap = previewQRWidth * TEXT_GAP_RATIO;
  const previewFontSize = previewQRWidth * FONT_SIZE_RATIO;

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Hidden QR Generator for Export Scaling */}
      <div className="hidden">
        {config.value && (
          <div ref={exportCanvasRef}>
            <QRCodeCanvas
              value={config.value}
              size={config.size} // Luôn tạo QR ở độ phân giải gốc để cực nét
              fgColor={config.fgColor}
              bgColor="transparent"
              level={config.level}
              includeMargin={false}
            />
          </div>
        )}
      </div>

      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-indigo-200 shadow-lg">
              <QrCode className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">Smart QR Studio</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider border border-indigo-100">SafeScan v2.0</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-7 space-y-6">
          {/* Section: URL & Basic Meta */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <Plus className="w-5 h-5 text-indigo-500" />
              Nội dung mã QR
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Đường dẫn (URL)</label>
                <div className="relative">
                  <input
                    type="url"
                    name="value"
                    value={config.value}
                    onChange={handleInputChange}
                    placeholder="https://example.com"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 pr-32"
                  />
                  <button
                    onClick={handleAnalyze}
                    disabled={isAnalyzing || !config.value}
