                            <button onClick={() => setConfig(prev => ({...prev, bgImageFit: 'contain'}))} className={`flex-1 py-1 text-[9px] font-black rounded ${config.bgImageFit === 'contain' ? 'bg-slate-900 text-white' : 'text-slate-400'}`}>CONTAIN</button>
