                           <input type="range" name="bgImageScale" min="0.1" max="3" step="0.05" value={config.bgImageScale} onChange={handleInputChange} className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none accent-indigo-600" />
                        </div>
