              </div>

              {/* Formatting */}
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Định dạng</label>
                    <select value={exportFormat} onChange={(e) => setExportFormat(e.target.value as any)} className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500">
                      <option value="png">PNG (High Quality)</option>
                      <option value="jpeg">JPEG (Optimized)</option>
                      <option value="svg">SVG (Vector)</option>
                    </select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Màu chủ đạo</label>
                    <div className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-xl">
                      <input type="color" name="fgColor" value={config.fgColor} onChange={handleInputChange} className="w-6 h-6 rounded cursor-pointer border-0 bg-transparent" />
                      <input type="text" name="fgColor" value={config.fgColor} onChange={handleInputChange} className="flex-1 text-xs font-mono uppercase outline-none" />
                    </div>
                 </div>
              </div>
            </div>
          </div>
        </div>

        {/* Sidebar: Real-time Preview */}
        <div className="lg:col-span-5">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-200 sticky top-24 flex flex-col items-center">
            <div className="w-full text-center mb-6">
              <span className="inline-block px-3 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold uppercase tracking-widest mb-2 border border-indigo-100">Live Preview</span>
              <h3 className="text-xl font-bold text-slate-900 truncate px-4">{config.title || "Smart QR Studio"}</h3>
              <p className="text-xs text-slate-400 mt-1 truncate px-4">{config.description || "Design your professional QR code"}</p>
            </div>

            <div className="relative w-full aspect-square bg-white rounded-2xl shadow-inner border border-slate-100 overflow-hidden flex items-center justify-center">
              {/* BG Preview */}
              <div className="absolute inset-0 z-0">
                {config.bgImage && (
                  <img 
                    src={config.bgImage} 
                    className="w-full h-full" 
                    style={{ 
                      opacity: config.bgImageOpacity,
                      objectFit: config.bgImageFit,
                      transform: `scale(${config.bgImageScale})`
                    }}
                    alt="" 
                  />
                )}
              </div>

              {/* QR Preview Group */}
              {config.value ? (
                <div 
                  className="relative z-10 flex flex-col items-center shadow-2xl transition-all duration-300"
                  style={{ 
                    backgroundColor: config.bgColor,
                    padding: `${previewInternalMargin}px`,
                    borderRadius: `${previewQRWidth * 0.05}px`,
                    width: `${previewQRWidth}px`
                  }}
                >
                  <QRCodeCanvas
                    value={config.value}
                    size={previewActualQRSize}
                    fgColor={config.fgColor}
                    bgColor="transparent"
                    level={config.level}
                  />
                  <div 
                    className="font-bold tracking-tight text-center" 
                    style={{ 
                      marginTop: `${previewTextGap}px`,
                      color: config.fgColor,
                      fontSize: `${previewFontSize}px`,
                    }}
                  >
                    {DISPLAY_TEXT}
                  </div>
                </div>
              ) : (
                <div className="bg-slate-50/80 backdrop-blur-sm border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center z-10">
                  <QrCode className="w-12 h-12 text-slate-300 mx-auto mb-2" />
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Đang chờ nội dung...</p>
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-3 w-full mt-8">
              <button
                onClick={handleDownload}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 disabled:bg-slate-200 transition-all shadow-lg active:scale-95"
              >
                <Download className="w-5 h-5" /> EXPORT
              </button>
              <button
                onClick={handleSave}
                disabled={!config.value}
                className="flex items-center justify-center gap-2 px-6 py-4 border border-slate-200 text-slate-700 rounded-2xl font-bold hover:bg-slate-50 disabled:opacity-50 transition-all"
              >
                <History className="w-5 h-5" /> LƯU LẠI
              </button>
            </div>

            {config.value && (
              <div className="mt-6 w-full p-4 bg-slate-50 rounded-2xl flex items-center justify-between gap-4 border border-slate-100">
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Source Link</p>
                  <p className="text-xs font-semibold text-slate-600 truncate">{config.value}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={handleCopy} className="p-2 hover:bg-white rounded-lg transition-colors text-slate-400 hover:text-indigo-600">
                    {copied ? <CheckCircle2 className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Footer System Info */}
      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-slate-200 px-4 py-3 z-20">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Hệ thống xử lý thông minh</p>
          </div>
          <div className="flex gap-4 items-center">
             <p className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 uppercase tracking-widest">Engine: v2.0.1 HighRes</p>
