export type BarcodeType = 
  | 'qrcode' 
  | 'CODE128' 
  | 'CODE39' 
  | 'EAN13' 
  | 'UPC' 
  | 'ITF14' 
  | 'MSI' 
  | 'pharmacode';

export interface QRCodeConfig {
  value: string;
  barcodeType: BarcodeType; // Loại mã vạch
  size: number;
  fgColor: string;
  bgColor: string;
  level: 'L' | 'M' | 'Q' | 'H'; // Chỉ dùng cho QR
  includeMargin: boolean;
  title?: string;
  description?: string;
  bgImage?: string;
  bgImageOpacity: number;
  bgImageFit: 'cover' | 'contain';
  bgImageScale: number;
  qrScale: number;
}

export interface GeneratedQR extends QRCodeConfig {
  id: string;
  createdAt: number;
}

export interface AISuggestion {
  title: string;
  description: string;
  suggestedColor: string;
}

