// Helper Component để render Linear Barcode
const LinearBarcode = ({ config }: { config: QRCodeConfig }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (canvasRef.current && config.value) {
      try {
        setError(null);
        JsBarcode(canvasRef.current, config.value, {
          format: config.barcodeType as any,
          lineColor: config.fgColor,
          background: 'transparent',
          displayValue: true,
          width: 2,
          height: 100,
          margin: 0
        });
      } catch (e) {
        setError("Dữ liệu không hợp lệ cho loại mã này");
      }
    }
  }, [config.value, config.barcodeType, config.fgColor]);

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-40 w-full text-red-500 gap-2">
        <AlertCircle className="w-8 h-8" />
        <span className="text-xs font-bold text-center px-4">{error}</span>
      </div>
    );
  }

  return <canvas ref={canvasRef} className="max-w-full h-auto" />;
};

