                    <div className={`absolute -top-20 -right-20 w-64 h-64 rounded-full mix-blend-multiply filter blur-3xl opacity-20 dark:opacity-40 ${def.colorClass.replace('bg-', 'bg-').split(' ')[0]}`} />
                    <div className="absolute -bottom-20 -left-20 w-64 h-64 rounded-full bg-purple-200 dark:bg-purple-900 mix-blend-multiply filter blur-3xl opacity-20 dark:opacity-40" />

                    <div className="z-10 w-full flex flex-col items-center">
                        <div className="mb-6 text-center">
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white">{config.title || "Preview"}</h3>
                            <p className="text-sm text-slate-400">{config.size}x{config.size}px</p>
                        </div>

                        {/* PREVIEW CONTAINER */}
                        <div className="relative w-full aspect-square bg-white rounded-3xl shadow-2xl border border-slate-50 dark:border-slate-700 overflow-hidden flex items-center justify-center mb-8">
                             {/* BG Layer */}
                             <div className="absolute inset-0 z-0">
                                {(useBgImage && config.bgImage) ? (
                                    <img 
                                        src={config.bgImage} 
                                        className="w-full h-full transition-transform duration-500" 
                                        style={{ 
                                            opacity: config.bgImageOpacity, 
                                            objectFit: config.bgImageFit, 
                                            transform: `scale(${config.bgImageScale})` 
                                        }} 
                                    />
                                ) : (
                                    <div className="w-full h-full bg-slate-50/50 dark:bg-slate-900/50 flex items-center justify-center">
                                        <div className={`w-full h-full opacity-10 ${def.colorClass}`} />
                                    </div>
                                )}
                             </div>

                             {/* Code Layer */}
                             {config.value ? (
                                <div 
                                    className="relative z-10 flex flex-col items-center shadow-lg transition-all duration-300"
                                    style={{ 
                                        backgroundColor: config.bgColor,
                                        padding: `${previewInternalMargin}px`,
                                        borderRadius: `${previewQRWidth * 0.05}px`,
                                        width: `${previewQRWidth}px`,
                                        height: config.barcodeType === 'qrcode' ? `${previewQRWidth}px` : 'auto',
                                        minHeight: config.barcodeType !== 'qrcode' ? '100px' : undefined
                                    }}
                                >
                                    {config.barcodeType === 'qrcode' ? (
                                        <QRCodeCanvas
                                            value={config.value}
                                            size={previewQRWidth - (previewInternalMargin * 2)}
                                            fgColor={config.fgColor}
                                            bgColor="transparent"
                                            level={config.level}
                                            includeMargin={false}
                                        />
                                    ) : (
                                        <LinearBarcode config={config} />
                                    )}

                                    {config.barcodeType === 'qrcode' && (
                                        <div 
                                            className="font-bold tracking-tight text-center whitespace-nowrap overflow-hidden" 
                                            style={{ 
                                                marginTop: `${previewTextGap}px`, 
                                                color: config.fgColor, 
                                                fontSize: `${previewFontSize}px`, 
                                                width: '100%' 
                                            }}
                                        >
                                            Quét để truy cập
                                        </div>
                                    )}
                                </div>
                             ) : (
                                <div className="z-10 text-center opacity-30">
                                    <ScanBarcode className="w-16 h-16 mx-auto mb-2 dark:text-white" />
                                    <span className="text-xs font-bold uppercase dark:text-white">No Data</span>
                                </div>
                             )}
                        </div>

                        {/* Actions */}
                        <div className="w-full space-y-3">
                             <div className="flex gap-2 mb-2">
                                {(['png', 'jpeg', 'svg', 'pdf'] as ExportFormat[]).map(fmt => (
                                    <button 
                                        key={fmt}
                                        onClick={() => setExportFormat(fmt)}
                                        className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all border ${exportFormat === fmt ? 'bg-slate-800 text-white border-slate-800 dark:bg-white dark:text-slate-900' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300 dark:bg-slate-700 dark:border-slate-600 dark:text-slate-300'}`}
                                    >
                                        {fmt}
                                    </button>
                                ))}
                             </div>

                             <button 
                                onClick={() => handleDownload()}
                                disabled={!config.value}
                                className="w-full py-4 bg-slate-800 text-white dark:bg-white dark:text-slate-900 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-slate-900 dark:hover:bg-slate-200 transition-colors shadow-lg disabled:opacity-50 disabled:shadow-none"
                             >
                                <Download className="w-5 h-5" /> Tải về {exportFormat.toUpperCase()}
                             </button>

                             <button 
                                onClick={handleSave}
                                disabled={!config.value}
                                className="w-full py-4 bg-white dark:bg-slate-700 text-slate-700 dark:text-white border border-slate-200 dark:border-slate-600 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-slate-50 dark:hover:bg-slate-600 transition-colors"
                             >
                                <History className="w-5 h-5 text-indigo-500" /> {editingId ? 'Cập nhật mã' : 'Lưu vào thư viện'}
                             </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Hidden Canvas for QR Export */}
        <div className="hidden">
           {config.value && config.barcodeType === 'qrcode' && (
             <div ref={exportCanvasRef}>
               <QRCodeCanvas
                 value={config.value}
                 size={config.size} 
                 fgColor={config.fgColor}
                 bgColor="transparent"
                 level={config.level}
                 includeMargin={false}
               />
             </div>
           )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#fdfbf7] dark:bg-slate-950 pb-20 transition-colors duration-500">
      <Header />
      {view === 'dashboard' ? <Dashboard /> : <Editor />}
    </div>
  );
}

