// --- Helper Component: Linear Barcode Render ---
const LinearBarcode = ({ config, className }: { config: QRCodeConfig, className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (canvasRef.current && config.value) {
      try {
        setError(null);
        JsBarcode(canvasRef.current, config.value, {
          format: config.barcodeType as any,
          lineColor: config.fgColor,
          background: 'transparent',
          displayValue: true,
          width: 2,
          height: 100,
          margin: 0,
          fontSize: 16,
          fontOptions: "bold",
          font: "monospace"
        });
      } catch (e) {
        setError("Dữ liệu không hợp lệ");
      }
    }
  }, [config.value, config.barcodeType, config.fgColor]);

  if (error) {
    return (
      <div className={`flex flex-col items-center justify-center p-4 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-400 ${className}`}>
        <AlertCircle className="w-6 h-6 mb-1" />
        <span className="text-[10px] font-bold text-center uppercase tracking-wider">{error}</span>
      </div>
    );
  }

  return <canvas ref={canvasRef} className={`max-w-full h-auto ${className}`} />;
};

// --- Main App Component ---
export default function App() {
  // State: Theme
  const [theme, setTheme] = useState<ThemeMode>('system');

  // State: Navigation & Data
  const [view, setView] = useState<'dashboard' | 'editor'>('dashboard');
  const [history, setHistory] = useState<GeneratedQR[]>([]);

  // State: Editor Configuration
  const [config, setConfig] = useState<QRCodeConfig>(DEFAULT_CONFIG);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [useBgImage, setUseBgImage] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [bgSourceType, setBgSourceType] = useState<'upload' | 'url'>('upload');
  const [bgUrlInput, setBgUrlInput] = useState('');

  // State: UI Feedback
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [exportFormat, setExportFormat] = useState<ExportFormat>('png');

  // Refs
  const exportCanvasRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Constants for Rendering
  const INTERNAL_MARGIN_RATIO = 0.05;
  const TEXT_GAP_RATIO = config.barcodeType === 'qrcode' ? 0.05 : 0;
  const FONT_SIZE_RATIO = 0.08;

  // --- Effects ---

  // Theme Effect
  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');

    if (theme === 'system') {
      const systemTheme = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
      root.classList.add(systemTheme);
    } else {
      root.classList.add(theme);
    }
  }, [theme]);

  useEffect(() => {
    const saved = localStorage.getItem('pastel_code_history');
    if (saved) {
      try { setHistory(JSON.parse(saved)); } catch (e) { console.error(e); }
    }

    // Load theme if saved
    const savedTheme = localStorage.getItem('app_theme');
    if (savedTheme) {
        setTheme(savedTheme as ThemeMode);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('pastel_code_history', JSON.stringify(history));
  }, [history]);

  // --- Actions ---

  const cycleTheme = () => {
    setTheme(prev => {
        const next = prev === 'system' ? 'light' : prev === 'light' ? 'dark' : 'system';
        localStorage.setItem('app_theme', next);
        return next;
    });
  };

  const handleSelectType = (type: BarcodeType) => {
    setConfig({
      ...DEFAULT_CONFIG,
      barcodeType: type,
      value: '', 
      qrScale: type === 'qrcode' ? 0.5 : 0.8
    });
    setEditingId(null);
    setUseBgImage(false);
    setView('editor');
  };

  const handleEdit = (item: GeneratedQR) => {
    setConfig(item);
    setEditingId(item.id);
    setUseBgImage(!!item.bgImage);
    setView('editor');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa mã này khỏi thư viện?')) {
      setHistory(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleSave = () => {
    if (!config.value) return;

    if (editingId) {
      setHistory(prev => prev.map(item => item.id === editingId ? { ...config, id: editingId, createdAt: Date.now() } : item));
      setEditingId(null);
      alert("Đã cập nhật mã thành công!");
    } else {
      setHistory(prev => [{ ...config, id: crypto.randomUUID(), createdAt: Date.now() }, ...prev]);
      alert("Đã lưu vào thư viện!");
    }
  };

  const handleBackToDashboard = () => {
    setView('dashboard');
    setEditingId(null);
  };

  const handleAnalyze = async () => {
    if (!config.value) return alert("Vui lòng nhập nội dung");
    setIsAnalyzing(true);
    try {
      const suggestion = await getSmartContext(config.value);
      setConfig(prev => ({
        ...prev,
        title: suggestion.title,
        description: suggestion.description,
        fgColor: suggestion.suggestedColor
      }));
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Rendering Logic (Canvas Generation) ---
  const loadImage = (src: string): Promise<HTMLImageElement> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  };

  const generateCanvas = async (configToRender: QRCodeConfig): Promise<HTMLCanvasElement | null> => {
    const canvasSize = configToRender.size;
    const qrGroupWidth = canvasSize * configToRender.qrScale;
    const internalMargin = qrGroupWidth * INTERNAL_MARGIN_RATIO;
    const maxContentWidth = qrGroupWidth - (internalMargin * 2);

    // Calculate Height
    let contentHeight = maxContentWidth; 
    const tempCanvas = document.createElement('canvas');
    if (configToRender.barcodeType !== 'qrcode') {
        try {
            JsBarcode(tempCanvas, configToRender.value, {
                format: configToRender.barcodeType as any,
                width: 4, height: 200, displayValue: true, margin: 0, fontSize: 40
            });
            contentHeight = maxContentWidth * (tempCanvas.height / tempCanvas.width);
        } catch (e) { return null; }
    }

    const fontSize = configToRender.barcodeType === 'qrcode' ? qrGroupWidth * FONT_SIZE_RATIO : 0;
    const textGap = configToRender.barcodeType === 'qrcode' ? qrGroupWidth * TEXT_GAP_RATIO : 0;

    const patchH = contentHeight + textGap + fontSize + (internalMargin * 2);
    const patchW = qrGroupWidth;

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return null;

    canvas.width = canvasSize;
    canvas.height = canvasSize;

    // Background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Image Background
    if (configToRender.bgImage) {
      try {
        const bgImg = await loadImage(configToRender.bgImage);
        const ratioCanvas = canvas.width / canvas.height;
        const ratioImg = bgImg.width / bgImg.height;
        let drawScale = 1;

        if (configToRender.bgImageFit === 'cover') {
          drawScale = ratioCanvas > ratioImg ? canvas.width / bgImg.width : canvas.height / bgImg.height;
        } else {
          drawScale = ratioCanvas > ratioImg ? canvas.height / bgImg.height : canvas.width / bgImg.width;
        }

        const finalScale = drawScale * configToRender.bgImageScale;
        const dw = bgImg.width * finalScale;
        const dh = bgImg.height * finalScale;
        const dx = (canvas.width - dw) / 2;
        const dy = (canvas.height - dh) / 2;

        ctx.save();
        ctx.globalAlpha = configToRender.bgImageOpacity;
        ctx.drawImage(bgImg, dx, dy, dw, dh);
        ctx.restore();
      } catch (e) { console.error("BG Error"); }
    }

    // Safe Patch
    const patchX = (canvas.width - patchW) / 2;
    const patchY = (canvas.height - patchH) / 2;
    const radius = qrGroupWidth * 0.05;

    ctx.fillStyle = configToRender.bgColor;
    ctx.beginPath();
    ctx.roundRect(patchX, patchY, patchW, patchH, radius);
    ctx.fill();

    // Content
    const drawContentX = patchX + internalMargin;
    const drawContentY = patchY + internalMargin;

    if (configToRender.barcodeType === 'qrcode') {
        const qrSourceCanvas = exportCanvasRef.current?.querySelector('canvas');
        if (qrSourceCanvas) {
             ctx.drawImage(qrSourceCanvas, drawContentX, drawContentY, maxContentWidth, maxContentWidth);
        }
    } else {
        const finalBarcodeCanvas = document.createElement('canvas');
        JsBarcode(finalBarcodeCanvas, configToRender.value, {
            format: configToRender.barcodeType as any,
            lineColor: configToRender.fgColor,
            width: 4, height: 200, displayValue: true, background: 'transparent', margin: 0, fontSize: 40
        });
        ctx.drawImage(finalBarcodeCanvas, drawContentX, drawContentY, maxContentWidth, contentHeight);
    }

    // Text (Only QR)
    if (configToRender.barcodeType === 'qrcode') {
        const DISPLAY_TEXT = "Quét để truy cập";
        ctx.fillStyle = configToRender.fgColor;
        ctx.font = `bold ${fontSize}px Lato, "Segoe UI", "Open Sans", sans-serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'top';
        ctx.fillText(DISPLAY_TEXT, canvas.width / 2, drawContentY + maxContentWidth + textGap);
    }
    return canvas;
  };

  const handleDownload = async (itemConfig: QRCodeConfig = config) => {
    if (!itemConfig.value) return;

    if (view === 'dashboard' && (itemConfig as any).id !== editingId) {
        handleEdit(itemConfig as GeneratedQR);
        return; 
    }

    const canvas = await generateCanvas(itemConfig);
    if (!canvas) return;

    const filename = `smart-barcode-${itemConfig.barcodeType}-${Date.now()}`;

    if (exportFormat === 'pdf') {
        const pdf = new jsPDF({
            orientation: 'portrait',
            unit: 'px',
            format: [canvas.width, canvas.height]
        });
        pdf.addImage(canvas.toDataURL('image/jpeg', 1.0), 'JPEG', 0, 0, canvas.width, canvas.height);
        pdf.save(`${filename}.pdf`);
    } else if (exportFormat === 'svg') {
        const link = document.createElement('a');
        link.download = `${filename}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
    } else {
        const mimeType = exportFormat === 'png' ? 'image/png' : 'image/jpeg';
        const link = document.createElement('a');
        link.download = `${filename}.${exportFormat}`;
        link.href = canvas.toDataURL(mimeType, 1.0);
        link.click();
    }
  };


  // --- Sub-Components ---

  const Header = () => (
    <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 transition-colors duration-300">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
            <button onClick={() => setView('dashboard')} className="flex items-center gap-2 group">
                <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-200 dark:shadow-none group-hover:scale-105 transition-transform">
                    <ScanBarcode className="text-white w-6 h-6" />
                </div>
                <div className="text-left">
                    <h1 className="text-lg font-bold text-slate-800 dark:text-slate-100 tracking-tight leading-none">Smart Barcode</h1>
                    <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">Generator AI</span>
                </div>
            </button>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => {
                        setView('dashboard');
                        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
                    }}
                    className="flex items-center gap-2 px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-300 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-all"
                >
                    <Layers className="w-4 h-4" />
                    <span className="hidden sm:inline">Thư viện mã</span>
                </button>

                <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-1" />

                <button 
                    onClick={cycleTheme}
                    className="p-2 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl transition-all relative overflow-hidden group"
                    title={`Theme: ${theme}`}
                >
                    {theme === 'light' && <Sun className="w-5 h-5" />}
                    {theme === 'dark' && <Moon className="w-5 h-5" />}
                    {theme === 'system' && <Monitor className="w-5 h-5" />}
                </button>
            </div>
        </div>
    </header>
  );

  const Dashboard = () => (
    <div className="max-w-6xl mx-auto px-4 py-8 animate-in fade-in duration-500">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-extrabold text-slate-800 dark:text-slate-100 tracking-tight mb-2">Smart Barcode Generator AI</h1>
        <p className="text-slate-500 dark:text-slate-400 text-lg">Chọn loại mã bạn muốn tạo hôm nay</p>
      </div>

      {/* Grid Cards */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 mb-16">
        {BARCODE_DEFINITIONS.map((def) => (
          <button
            key={def.type}
            onClick={() => handleSelectType(def.type)}
            className={`relative group p-6 rounded-3xl border border-white/50 dark:border-slate-800 shadow-sm hover:shadow-xl transition-all duration-300 flex flex-col items-center text-center gap-4 ${def.colorClass} hover:-translate-y-1`}
          >
            <div className={`p-4 bg-white/80 dark:bg-slate-800/80 backdrop-blur-sm rounded-2xl shadow-sm ${def.iconClass} group-hover:scale-110 transition-transform`}>
              {def.illustration}
            </div>
            <div>
