// --- Helper Component: Linear Barcode Render ---
const LinearBarcode = ({ config, className }: { config: QRCodeConfig, className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (canvasRef.current && config.value) {
      try {
        setError(null);
        JsBarcode(canvasRef.current, config.value, {
          format: config.barcodeType as any,
          lineColor: config.fgColor,
          background: 'transparent',
          displayValue: true,
          width: 2,
          height: 100,
          margin: 0,
          fontSize: 16,
          fontOptions: "bold",
          font: "monospace"
        });
      } catch (e) {
        setError("Dữ liệu không hợp lệ");
      }
    }
  }, [config.value, config.barcodeType, config.fgColor]);

  if (error) {
    return (
      <div className={`flex flex-col items-center justify-center p-4 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-400 ${className}`}>
        <AlertCircle className="w-6 h-6 mb-1" />
        <span className="text-[10px] font-bold text-center uppercase tracking-wider">{error}</span>
      </div>
    );
  }

  return <canvas ref={canvasRef} className={`max-w-full h-auto ${className}`} />;
};

// --- Main App Component ---
export default function App() {
