                        <div>
                            <h2 className={`text-2xl font-bold ${def.iconClass}`}>{def.label} Generator</h2>
                            <p className="text-sm opacity-80 font-medium">{def.description}</p>
                        </div>
                    </div>
                </div>

                {/* Input Section */}
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Dữ liệu nội dung</label>
                    <div className="relative">
                        <input
                            type="text"
                            name="value"
                            value={config.value}
