                    </div>
                </div>
            </div>
        </div>

        {/* Hidden Canvas for QR Export */}
        <div className="hidden">
           {config.value && config.barcodeType === 'qrcode' && (
             <div ref={exportCanvasRef}>
               <QRCodeCanvas
                 value={config.value}
                 size={config.size} 
                 fgColor={config.fgColor}
                 bgColor="transparent"
                 level={config.level}
                 includeMargin={false}
               />
             </div>
           )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#fdfbf7] pb-20 transition-colors duration-500">
      <Header />
      {view === 'dashboard' ? <Dashboard /> : view === 'library' ? <Library /> : <Editor />}
    </div>
  );
}

