  };

  return (
    <div className="min-h-screen bg-[#fdfbf7] pb-20 transition-colors duration-500">
      <Header />
      {view === 'dashboard' ? <Dashboard /> : view === 'library' ? <Library /> : <Editor />}
    </div>
  );
}

