// --- vCard Utilities ---
interface VCardData {
  firstName: string;
  lastName: string;
  phone: string;
  email: string;
  website: string;
  company: string;
  job: string;
  street: string;
  city: string;
  country: string;
}

const parseVCard = (str: string): VCardData => {
  const lines = str.split('\n');
  const getVal = (p: string) => {
    const line = lines.find(l => l.startsWith(p));
    return line ? line.split(':').slice(1).join(':').trim() : '';
  };

  // N:LastName;FirstName;;;
  const nVal = getVal('N:');
  const nParts = nVal.split(';');

  // ADR:;;Street;City;;;Country
  const adrVal = getVal('ADR:');
  const adrParts = adrVal.split(';');

  // TEL;TYPE=CELL: or just TEL:
  const telLine = lines.find(l => l.startsWith('TEL'));
  const tel = telLine ? telLine.split(':').slice(1).join(':').trim() : '';

  return {
    lastName: nParts[0] || '',
    firstName: nParts[1] || '',
    company: getVal('ORG:'),
    job: getVal('TITLE:'),
    phone: tel,
    email: getVal('EMAIL:'),
    website: getVal('URL:'),
    street: adrParts[2] || '',
    city: adrParts[3] || '',
    country: adrParts[6] || ''
  };
};

const generateVCard = (d: VCardData): string => {
  // Minimal vCard 3.0
  return `BEGIN:VCARD
VERSION:3.0
N:${d.lastName};${d.firstName};;;
FN:${d.firstName} ${d.lastName}
ORG:${d.company}
TITLE:${d.job}
TEL;TYPE=CELL:${d.phone}
EMAIL:${d.email}
URL:${d.website}
ADR:;;${d.street};${d.city};;;${d.country}
END:VCARD`;
};

// --- Helper Component: Debounced Input ---
const DebouncedInput = ({ 
  value, 
  onChange, 
  className, 
  placeholder,
  disabled 
}: { 
  value: string, 
  onChange: (val: string) => void, 
  className?: string,
  placeholder?: string,
  disabled?: boolean
}) => {
  const [localValue, setLocalValue] = useState(value);

  useEffect(() => {
    setLocalValue(value);
  }, [value]);

  useEffect(() => {
    const handler = setTimeout(() => {
      if (localValue !== value) {
        onChange(localValue);
      }
    }, 300); // 300ms debounce

    return () => clearTimeout(handler);
  }, [localValue]);

  return (
    <input
      type="text"
      value={localValue}
      onChange={(e) => setLocalValue(e.target.value)}
      className={className}
      placeholder={placeholder}
      disabled={disabled}
    />
  );
};

// --- Helper Component: Linear Barcode Render (Preview Only) ---
const LinearBarcode = ({ config, className }: { config: QRCodeConfig, className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (canvasRef.current && config.value) {
      try {
        setError(null);
        // Force manual rendering logic? No, preview can just use standard jsbarcode for speed
        // But for consistency we might want to mirror the canvas logic. 
        // For now, keep simple Preview using JsBarcode standard.
        JsBarcode(canvasRef.current, config.value, {
          format: config.barcodeType as any,
          lineColor: config.fgColor,
          background: 'transparent',
          displayValue: true, 
          width: 2,
          height: 100,
          margin: 0,
          fontSize: config.codeFontSize || 20, 
          fontOptions: "bold",
          font: config.codeFont
        });
      } catch (e) {
        setError("Dữ liệu không hợp lệ");
      }
    }
  }, [config.value, config.barcodeType, config.fgColor, config.codeFont, config.codeFontSize]);

  if (error) {
    return (
      <div className={`flex flex-col items-center justify-center p-4 bg-red-50 rounded-lg text-red-400 ${className}`}>
        <AlertCircle className="w-6 h-6 mb-1" />
        <span className="text-[10px] font-bold text-center uppercase tracking-wider">{error}</span>
      </div>
    );
  }

  return <canvas ref={canvasRef} className={`max-w-full h-auto ${className}`} />;
};

